I found out that this happens if I put an CircularProgressIndicator with opacity 0.

Sometimes you don't need to put it in background at all.

Hope this is related to this issue

Edit: this only happens with skia consistently, I don't know if this can happen with impeller. I have personally not encountered it.

```
class TestScreen extends StatefulWidget {
  const TestScreen({Key? key}) : super(key: key);

  @override
  _TestScreenState createState() => _TestScreenState();
}

class _TestScreenState extends State<TestScreen> {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Container(
        color: Colors.black,
        child: Stack(
          children: [
            Padding(
              padding: const EdgeInsets.only(top: 200),
              child: Stack(
                children: [_grid()],
              ),
            ),
            const Opacity(
              opacity: 0,
              child: CircularProgressIndicator(strokeWidth: 5, color: Colors.blue),
            ),
          ],
        ),
      ),
    );
  }

  Widget _grid() {
    return Align(
      alignment: Alignment.topCenter,
      child: Container(
        color: Colors.grey[200],
        child: GridView.count(
          crossAxisCount: 3,
          padding: const EdgeInsets.all(8),
          childAspectRatio: 1.2,
          shrinkWrap: true,
          physics: const NeverScrollableScrollPhysics(),
          children: _gridChildren(),
        ),
      ),
    );
  }

  List<Widget> _gridChildren() {
    List<Widget> list = [];
    for (int i = 1; i <= 12; i++) {
      list.add(
        Opacity(
          opacity: 0.3,
          child: Container(
            decoration: BoxDecoration(
              color: Colors.white,
              boxShadow: [
                BoxShadow(
                  color: const Color(0xff002255).withOpacity(0.20),
                  blurRadius: 12,
                  spreadRadius: -1,
                  offset: const Offset(0, 3),
                )
              ],
            ),
            child: Center(
              child: Text(i.toString()),
            ),
          ),
        ),
      );
    }
    return list;
  }
}
```

